n','2026-04-16 17:04:47.845','2026-04-16 18:04:42.167'),(98,29,4,'VOICE','isEnrolled','false',NULL,'https://kkhc.tos-cn-beijing.volces.com/eps-juzibot/permanent/material/%36%39%62%38%63%61%34%38%37%34%31%33%64%64%63%31%66%61%64%37%39%34%32%34.silk','https://drh.likeduoduiyi.cn/homework/voice/d1ab71990efb40308c8ce2514ba4f146.mp3',25000,NULL,NULL,25000,0,'online_sql_20260416','admin','2026-04-16 17:04:47.845','2026-04-16 18:04:40.468'),(99,29,5,'VOICE','isEnrolled','false',NULL,'https://kkhc.tos-cn-beijing.volces.com/eps-juzibot/permanent/material/%36%39%62%38%63%61%34%39%31%64%37%39%64%33%33%64%32%63%32%34%35%64%63%63.silk','https://drh.likeduoduiyi.cn/homework/voice/5db4437ca0fb4f40a918e9c07065641e.mp3',35000,NULL,NULL,35000,0,'online_sql_20260416','admin','2026-04-16 17:04:47.845','2026-04-16 18:04:37.997'),(100,32,1,'RANDOM_EMOJI','','',NULL,NULL,NULL,NULL,NULL,NULL,2000,1,'online_sql_20260416','online_sql_20260416','2026-04-16 17:04:47.845','2026-04-16 17:04:47.845'),(101,33,1,'TEXT','','','看到你主动提交作业了，积极性太赞啦！[强]',NULL,NULL,NULL,NULL,NULL,2000,1,'online_sql_20260416','admin','2026-04-16 17:04:47.845','2026-04-16 17:04:47.845'),(127,20,2,'TEXT','','','以上是完成作业的奖励 《宝典》👆👆表现非常棒哦，同学，咱们坚持上课坚持练习。 不过也要记得多喝温水保护好嗓子哦，老师看好你[玫瑰]',NULL,NULL,NULL,NULL,NULL,2000,0,'admin','admin','2026-04-16 17:24:03.326','2026-04-16 17:24:18.547'),(128,21,1,'TEXT','','','同学你好，老师听了你发来的作业，能听出来喉咙打开的动作更熟练了，这个其实就是进步，老师为你的学习精神点赞，特别棒。',NULL,NULL,NULL,NULL,NULL,10000,1,'admin','admin','2026-04-16 17:34:44.624','2026-04-16 17:34:44.624'),(129,21,2,'TEXT','','','而且老师发现你把气息支撑的技法也融入进去了一些，虽然能听出来不是很熟练，不过整个歌曲的完成度又上了一个小小的台阶。继续加油吧！老师期待你有更大的进步，也期待你后面的作品~',NULL,NULL,NULL,NULL,NULL,6000,1,'admin','admin','2026-04-16 17:35:00.496','2026-04-16 17:35:00.496'),(130,23,3,'TEXT','lastDayCompleteHomeWork&&qwUserId_RLike','true&&default','同学又收到您的作业了，那结合这几天学到的技巧，老师觉得你是很有进步的，运用的也更好一些了，很棒啊。',NULL,NULL,NULL,NULL,NULL,10000,1,'admin','api','2026-04-16 17:44:02.507','2026-04-16 17:44:02.507'),(131,23,4,'TEXT','lastDayCompleteHomeWork&&qwUserId_RLike','true&&default','那今晚教学了三种呼吸技巧，主要是帮助您在唱歌儿的过程当中有气息的支持。这也是老师之前一直给大家强调的歌者必先善其气。那同时呢，锻炼咱们的气息。目前老师能听得出你在唱歌的过程当中呢。是在有意识的控制自己的气息，对不对？看来咱们课上学的方法对你是有帮助的啊。老师听出来了，非常的棒。',NULL,NULL,NULL,NULL,NULL,10000,1,'admin','api','2026-04-16 17:44:34.149','2026-04-16 17:44:34.149'),(132,23,5,'TEXT','lastDayCompleteHomeWork&&qwUserId_RLike','true&&default','那现在呀，老师建议您把学过的气球呼吸法还有吐丝法分别的多多练习呀。咱们课上学习的歌儿，或者是您自己喜欢的歌儿都可以带入到这两个方法当中去练习。等你练了两三天之后呢，你就会觉得用气去发声，不仅呢，能让咱们的身体更加舒服。在吐故纳新的过程当中，还会帮助咱们的身体促进新陈代谢。',NULL,NULL,NULL,NULL,NULL,10000,1,'admin','api','2026-04-16 17:44:55.615','2026-04-16 17:44:55.615'),(133,20,2,'TEXT','qwUserId_RLike','default','您这第一份作业呀，是一个非常棒的开头儿。老师给您点赞啊，那咱们学声乐呢，无论是刚开始唱的如何大胆的开口，就已经是超过了很多同学了啊。流水不争先，咱们争的是一个滔滔不绝对不对知识点有掌握。真是不错啊，那咱们在唱高音的时候呢，嘴巴的开合度还是可以再调整一下的。你看这个嘴巴打开的再大一点儿，咱们用开合法配合着就可以让声音更加的有空间感，听起来会更加饱满了。那以后唱歌儿就再也不会有大白嗓的情况了。',NULL,NULL,NULL,NULL,NULL,10000,1,'admin','admin','2026-04-16 17:46:29.587','2026-04-16 17:46:29.587'),(134,20,3,'TEXT','qwUserId_RLike','default','老师通过您的这第一份作业已经了解到您的嗓音情况了啊。您目前的演唱呢，是有一些卡顿和走调儿的那应该呀，也是跟咱们有点儿紧张，并且呢，对于歌曲还不是很熟悉导致的对不对？所以呢，您不用过于担心啊。现在呢，我们已经有了一个很好的开头儿。只要我们第一步迈出来了，那离成功就不远了。重要的是要有开头儿啊，那距离唱出好听的歌曲呢，也只是时间的问题了。那今天晚上啊，咱们会讲解了两个唱歌儿的万能技巧，也帮助您正确的打开了喉咙。接下来就一定要多多的复习，让这个方法。变成我们自己的歌唱习惯好吗？',NULL,NULL,NULL,NULL,NULL,10000,1,'admin','admin','2026-04-16 17:46:51.814','2026-04-16 17:46:51.814'),(135,20,4,'TEXT','qwUserId_RLike','default','因为您的基础还是比较薄弱的，那么在学习第一课的时候啊，可能难免会遇到一些问题。不过，您的学习态度非常的棒，老师也会一直关注您的学习的。咱们继续加油，有不懂的随时来找我',NULL,NULL,NULL,NULL,NULL,6000,1,'admin','admin','2026-04-16 17:47:47.941','2026-04-16 17:47:47.941'),(136,20,5,'PDF','','',NULL,'https://kkhc.tos-cn-beijing.volces.com/mh/permanent/material/2823f236-b985-44ca-a5ea-91657ebe17e2/%31%35%62%30%31%30%37%39%36%36%32%36%34%66%64%38%61%33%33%37%65%66%65%32%37%30%62%30%64%34%65%30.pdf','https://drh.likeduoduiyi.cn/homework/file/15b0107966264fd8a337efe270b0d4e0.pdf',NULL,'1.%E3%80%8A%E5%BC%80%E5%BC%80%E7%8B%AC%E5%AE%B6%E4%B9%90%E7%90%86%E3%80%8B.pdf',5486777,2000,0,'admin','admin','2026-04-16 17:48:17.145','2026-04-17 21:08:22.340'),(137,23,6,'TEXT','lastDayCompleteHomeWork&&qwUserId_RLike','false&&default','同学，你好。终于收到你的作业了啊，这是一个很棒的开头儿啊，那老师呢，也一直在关注您的学习情况。首先，您目前的歌唱状态呀，是非常好的。听得出你在唱歌儿的过程当中呢，是有意识的在控制自己的气息。说明您学的非常认真，老师为你点赞。',NULL,NULL,NULL,NULL,NULL,10000,1,'admin','api','2026-04-16 17:50:40.846','2026-04-16 17:50:40.846'),(138,23,7,'TEXT','lastDayCompleteHomeWork&&qwUserId_RLike','false&&default','今晚教学了三种呼吸技巧，那老师也给您来总结一下气球呼吸法。就像是啊，你想象自己在吹一个气球，然后呢，慢慢的吸气，然后呢，让我们这个腰腹部像气球一样膨胀起来，然后我们再慢慢的呼气。呼，让这个气球慢慢的这个气息呀，把这个气送出去啊，通过我们的口送出去，这样呢，是可以帮助你更好的控制气息的流量和速度的。',NULL,NULL,NULL,NULL,NULL,10000,1,'admin','api','2026-04-16 17:51:09.002','2026-04-16 17:51:09.002'),(139,23,8,'TEXT','lastDayCompleteHomeWork&&qwUserId_RLike','false&&default','吐丝法呢，就是想象自己在吐一根很长很长的丝线。我们用气息把这个丝线慢慢的吐出来。这样啊，就可以帮助你更好的去控制气息的稳定和连贯性',NULL,NULL,NULL,NULL,NULL,10000,1,'admin','api','2026-04-16 17:51:36.971','2026-04-16 17:51:36.971'),(140,23,9,'TEXT','lastDayCompleteHomeWork&&qwUserId_RLike','false&&default','现在呢，您的技巧运用还不是很熟练。那我们现在呢，要先把这个基础的气球呼吸法还有吐丝法，咱们多多练习起来。用我们课上的歌儿也行，或者说用您自己喜欢的歌儿都是可以的啊，都是可以带入这些方法去练习的。那我们先练两到3天来感受一下。你就会发现，我用这个气去发声啊，不仅我的身体很舒服了，而且呢，我的喉咙也不疼了，也不累了啊。并且在吐故纳新的这个吸气呼吸的过程当中，这个气会帮助我们身体。去促进新陈代谢的，对我们身体也是非常好的。所以呢，在学习的过程当中，不但能够让自己高兴，我们还能锻炼身体，是不是。',NULL,NULL,NULL,NULL,NULL,10000,1,'admin','api','2026-04-16 17:52:33.682','2026-04-16 17:52:33.682'),(141,23,10,'TEXT','lastDayCompleteHomeWork&&qwUserId_RLike','false&&default','明天晚上啊，我们会学习口鼻腔共鸣。咱们一定要大胆的开口唱啊，老师期待你的作业，还是会单独给您指导的好吗？加油哦。',NULL,NULL,NULL,NULL,NULL,7000,1,'admin','api','2026-04-16 17:52:56.260','2026-04-16 17:52:56.260'),(142,23,11,'PDF','lastDayCompleteHomeWork','false',NULL,'https://kkhc.tos-cn-beijing.volces.com/mh/permanent/material/3167bbee-19ff-4870-9106-0e1ee7b3e210/%37%35%64%61%62%32%34%39%66%37%62%34%34%31%31%37%62%32%64%36%34%32%32%66%36%64%36%31%38%36%37%36.pdf','https://drh.likeduoduiyi.cn/homework/file/75dab249f7b44117b2d6422f6d618676.pdf',NULL,'2.%E3%80%8A%E5%BC%80%E5%BC%80%E5%9F%BA%E6%9C%AC%E6%8A%80%E5%B7%A7%E3%80%8B.pdf',642347,2000,0,'admin','admin','2026-04-16 17:53:32.563','2026-04-16 17:53:53.346'),(143,23,11,'PDF','','',NULL,'https://kkhc.tos-cn-beijing.volces.com/mh/permanent/material/a66ae61c-1b22-4194-b56f-eac95484a170/%36%61%66%64%33%37%61%33%33%37%62%38%34%36%31%66%39%36%31%66%64%63%61%36%32%30%65%66%36%37%39%39.pdf','https://drh.likeduoduiyi.cn/homework/file/6afd37a337b8461f961fdca620ef6799.pdf',NULL,'2.%E3%80%8A%E5%BC%80%E5%BC%80%E5%9F%BA%E6%9C%AC%E6%8A%80%E5%B7%A7%E3%80%8B.pdf',642347,2000,0,'admin','admin','2026-04-16 17:54:04.689','2026-04-17 21:06:30.812'),(144,24,1,'TEXT','','','老师认真听了你发来的作业，整体好听度很高，不得不说比上次交的作业进步不小，老师很欣慰',NULL,NULL,NULL,NULL,NULL,5000,1,'admin','admin','2026-04-16 17:54:42.344','2026-04-16 17:54:42.344'),(145,24,2,'TEXT','','','同时呢，老师也建议你在一些高音部分要注意发声技巧，多多练习发声技巧，避免用力过度，保护嗓子。其实做什么都讲究熟练，咱们学习的技法是一样的，老师虽然可以让你快速的学会方法，快速改善问题，却不能帮你掌握熟练，所以下去可以多练习练习，比如做家务的时候，晨练的时候都可以，整体来说是有进步的，继续加油呀！',NULL,NULL,NULL,NULL,NULL,11000,1,'admin','admin','2026-04-16 17:55:08.308','2026-04-16 17:55:08.308'),(146,25,1,'RANDOM_EMOJI','','',NULL,NULL,NULL,NULL,NULL,NULL,2000,1,'admin','admin','2026-04-16 17:55:32.764','2026-04-16 17:55:32.764'),(147,22,1,'RANDOM_EMOJI','','',NULL,NULL,NULL,NULL,NULL,NULL,2000,1,'admin','admin','2026-04-16 17:55:45.511','2026-04-16 17:55:45.511'),(148,26,1,'TEXT','lastDayCompleteHomeWork','true','收到您的练唱啦，下面是详细点评和学习奖励，请查收',NULL,NULL,NULL,NULL,NULL,7000,1,'admin','admin','2026-04-16 17:56:54.940','2026-04-16 17:56:54.940'),(149,26,2,'VOICE','lastDayCompleteHomeWork&&qwUserId_RLike','true&&default',NULL,'https://kkhc.tos-cn-beijing.volces.com/eps-juzibot/permanent/material/%36%39%65%30%62%32%66%36%66%31%66%32%37%31%33%34%32%37%30%34%36%32%30%32.silk','https://drh.likeduoduiyi.cn/homework/voice/fe22ad088141459c8fd90733d9b02c44.m4a',87000,NULL,NULL,87000,0,'admin','api','2026-04-16 17:59:18.938','2026-04-22 18:09:18.634'),(150,26,3,'VOICE','lastDayCompleteHomeWork&&qwUserId_RLike','true&&default',NULL,'https://kkhc.tos-cn-beijing.volces.com/eps-juzibot/permanent/material/%36%39%65%30%62%32%66%38%33%38%37%36%30%32%65%64%37%64%63%32%31%66%36%37.silk','https://drh.likeduoduiyi.cn/homework/voice/671be73bfa1f4190b64e3b74b33226f0.m4a',222000,NULL,NULL,222000,0,'admin','api','2026-04-16 17:59:22.381','2026-04-22 18:09:18.751'),(151,26,4,'VOICE','lastDayCompleteHomeWork&&qwUserId_RLike','true&&default',NULL,'https://kkhc.tos-cn-beijing.volces.com/eps-juzibot/permanent/material/%36%39%65%30%62%32%66%62%66%31%66%32%37%31%33%34%32%37%30%34%36%32%62%66.silk','https://drh.likeduoduiyi.cn/homework/voice/047263a19d13406e966e96bc058f90f5.m4a',139000,NULL,NULL,139000,0,'admin','api','2026-04-16 17:59:24.028','2026-04-22 18:09:18.824'),(152,26,5,'TEXT','lastDayCompleteHomeWork','false','🤩收到您的作业啦，很棒哦',NULL,NULL,NULL,NULL,NULL,5000,1,'admin','admin','2026-04-16 18:00:43.295','2026-04-16 18:00:43.295'),(153,26,6,'VOICE','lastDayCompleteHomeWork&&qwUserId_RLike','false&&default',NULL,'https://kkhc.tos-cn-beijing.volces.com/eps-juzibot/permanent/material/%36%39%65%30%62%33%38%63%66%31%66%32%37%31%33%34%32%37%30%34%63%37%32%34.silk','https://drh.likeduoduiyi.cn/homework/voice/49adb90c0a95400083c2b509fa9efd6d.m4a',98000,NULL,NULL,98000,0,'admin','api','2026-04-16 18:01:49.377','2026-04-22 18:09:18.915'),(154,26,7,'VOICE','lastDayCompleteHomeWork&&qwUserId_RLike','false&&default',NULL,'https://kkhc.tos-cn-beijing.volces.com/eps-juzibot/permanent/material/%36%39%65%30%62%33%38%65%33%38%37%36%30%32%65%64%37%64%63%32%62%31%32%38.silk','https://drh.likeduoduiyi.cn/homework/voice/5b64a2f5e11f42fabf0b1887fd1cb4e0.m4a',142000,NULL,NULL,142000,0,'admin','api','2026-04-16 18:01:51.681','2026-04-22 18:09:19.016'),(155,26,8,'VOICE','lastDayCompleteHomeWork&&qwUserId_RLike','false&&default',NULL,'https://kkhc.tos-cn-beijing.volces.com/eps-juzibot/permanent/material/%36%39%65%30%62%33%39%30%66%31%66%32%37%31%33%34%32%37%30%34%63%39%37%39.silk','https://drh.likeduoduiyi.cn/homework/voice/3ed2799e535d474ca08941b62068553a.m4a',82000,NULL,NULL,82000,0,'admin','api','2026-04-16 18:01:53.474','2026-04-22 18:09:19.108'),(156,26,9,'VOICE','lastDayCompleteHomeWork&&qwUserId_RLike','false&&default',NULL,'https://kkhc.tos-cn-beijing.volces.com/eps-juzibot/permanent/material/%36%39%65%30%62%33%39%32%33%38%37%36%30%32%65%64%37%64%63%32%62%35%35%66.silk','https://drh.likeduoduiyi.cn/homework/voice/fad2e8a8184e4f288b0ae293123c0930.m4a',269000,NULL,NULL,269000,0,'admin','api','2026-04-16 18:01:55.866','2026-04-22 18:09:19.197'),(157,26,10,'PDF','','',NULL,'https://kkhc.tos-cn-beijing.volces.com/mh/permanent/material/380dd043-7b81-4d48-b46e-bb694e35f6d9/%61%32%38%38%31%62%33%37%66%38%30%35%34%65%39%35%62%36%34%61%62%65%63%30%34%31%30%66%32%38%65%61.pdf','https://drh.likeduoduiyi.cn/homework/file/a2881b37f8054e95b64abec0410f28ea.pdf',NULL,'3.《KTV麦霸宝典》.pdf',231681,6000,1,'admin','admin','2026-04-16 18:03:02.938','2026-04-16 18:03:02.938'),(158,27,1,'TEXT','','','同学，老师认真听了，咱们这次的作业的整体评分，要比上次高一些，老师可以给你具体分析一下，这次的进步其实得益于你的音乐感的提升以及发声技巧的运用，当然，这次在去运用技巧的时候也更自然了，但是，仍然要注意发声时的气息和音高掌控，个别部分还是需要加强练习和调整的。天之大这首歌难就难在用上鼻腔和共鸣去唱，只要能把这个技法掌握熟了，气息和音高也会表现的更好',NULL,NULL,NULL,NULL,NULL,9000,1,'admin','admin','2026-04-16 18:03:45.816','2026-04-16 18:03:45.816'),(159,27,2,'TEXT','','','老师也发现，咱们在节奏节拍方面，还是有一些不稳定。但没关系，第四节就要讲节奏的问题，到时候来跟着老师学一学、练一练，之后再唱，就能跟上节奏了、也会更加的有律动感了。加油！',NULL,NULL,NULL,NULL,NULL,8000,1,'admin','admin','2026-04-16 18:03:58.784','2026-04-16 18:03:58.784'),(160,29,2,'TEXT','qwUserId_RLike','default','收到您的作业了，老师听出你的节奏感是有明显的提升的，非常好。这首歌的难点就在于节奏，但是节奏这个知识点本身是很难的，节奏感也不是能短时间快速解决的，所以在课上有意识的心灵节奏打拍子了，这就非常好。不过在唱的过程中，咬字有一些重，其实当我们再去唱快歌儿的时候，不用把字咬的太重，不要读的那么圆了。当你习惯了舌尖灵活发音的时候，唱快歌也就不会觉得慌乱了。',NULL,NULL,NULL,NULL,NULL,9000,1,'admin','api','2026-04-16 18:09:01.717','2026-04-16 18:09:01.717'),(161,29,3,'TEXT','qwUserId_RLike','default','你在唱这首歌时，大部分音都很稳，课上听的也很认真，但有个别音还是没有唱准确，问题主要是出在气息上，你的气息并没有很好的稳定住你的声音，导致有的音会倒下来或偏出去，听起来就不那么准确。声乐是一门需要长期练习的技术，跟着老师系统的学和练，才能越唱越好听。奖励发给您，期待您在开开华彩的进步，加油。',NULL,NULL,NULL,NULL,NULL,12000,1,'admin','api','2026-04-16 18:09:15.632','2026-04-16 18:09:15.632'),(162,29,4,'PDF','','',NULL,'https://kkhc.tos-cn-beijing.volces.com/mh/permanent/material/3d58f6d5-38fb-41e2-87d2-0c7ddf24878e/%65%61%61%34%32%35%64%32%32%61%36%61%34%63%31%61%39%30%63%34%66%64%33%64%32%37%31%33%32%34%65%33.pdf','https://drh.likeduoduiyi.cn/homework/file/eaa425d22a6a4c1a90c4fd3d271324e3.pdf',NULL,'4.%E3%80%8A%E5%BC%80%E5%BC%80%E5%90%8D%E5%AE%B6%E6%8A%80%E5%B7%A7%E5%AE%9D%E5%85%B8%E3%80%8B.pdf',780037,2000,0,'admin','admin','2026-04-16 18:09:48.431','2026-04-17 21:10:59.519'),(163,30,1,'TEXT','isEnrolled&&qwUserId_RLike','true&&default','刚才听了你的声音了，你在唱这首歌的时候呀，大部分的音都很稳。但是老师用专业的耳朵去分辨了一下啊，还是能听出有个别的音啊，还是需要加强。如果想要把音准完全的唱好。你就一定要多多关注你这个气息上的问题啊，因为老师听到你这个气息呢，目前还不是很稳。如果你的气息不稳，你就没有办法很好的去稳定住你的声音，那么就会导致你的声音呢，偶尔会倒下来或者是偏出去，听起来就不准确了对吧。那我们结合今天学习的这个识谱子啊，还有音高的这个概念，其实呢，你已经对音准的知识开始入门儿了',NULL,NULL,NULL,NULL,NULL,10000,1,'admin','api','2026-04-16 18:10:28.031','2026-04-16 18:10:28.031'),(164,30,2,'TEXT','isEnrolled&&qwUserId_RLike','false&&default','同学，你好，你在唱这首歌时，大部分音都很稳，课上听的也很认真。但有个别音还是没有唱准确。问题主要是出在气息上，你的气息并没有很好的稳定住你的声音，导致有的音会倒下来或偏出去，听起来就不那么准确。',NULL,NULL,NULL,NULL,NULL,10000,1,'admin','api','2026-04-16 18:17:10.848','2026-04-16 18:17:10.848'),(165,30,3,'TEXT','isEnrolled&&qwUserId_RLike','false&&default','关于气息能力的提升，需要用方法坚持练习，因为气息是一门大技术，需要我们进行长期训练，并不是几天内就能完全掌握的，以你目前的情况，需要把气息练习列为重点学习方向。因为。气息能帮助你从根本上解决音准问题。气息，老师的系统课里会有更详细的教学，你要跟老师继续学吗？',NULL,NULL,NULL,NULL,NULL,10000,1,'admin','api','2026-04-16 18:19:34.343','2026-04-16 18:19:34.343'),(166,30,4,'TEXT','isEnrolled&&qwUserId_RLike','true&&default','而关于气息能力的这部分的提升呢，还是需要用方法坚持的去练习的。因为气息呢，它是一门大技术啊，需要我们进行长期的训练，并不是说几天内就能完全掌握的。当然你目前的演唱还是很不错的，我们只需要把这个气息的练习去列为一个重点的学习方向，就一定能唱的更好，因为气息能够帮助你啊，从根本上去解决音准的问题啊，一定要记住这一点。那最后呢，老师还想给你一个小提示，一起来回忆一下前五节课你都学了哪些技巧啊，想一想我们在脑子里过一遍。因为下节课上课的时候呀，会对你帮助很大的，我们一起做好准备来迎接最后一节课吧。老师也准备了一场美丽的烟花秀，在课上等着你。那我们课上见啊。',NULL,NULL,NULL,NULL,NULL,10000,1,'admin','online_sql_20260423_remove_zhangman','2026-04-16 18:20:45.771','2026-04-23 16:42:47.000'),(167,30,5,'PDF','','',NULL,'https://kkhc.tos-cn-beijing.volces.com/mh/permanent/material/1f1ae695-d59d-46ca-afc1-60e535ad40b6/%35%32%33%36%38%62%37%62%64%36%33%33%34%31%36%35%38%38%62%31%35%63%36%39%36%36%30%39%33%63%66%31.pdf','https://drh.likeduoduiyi.cn/homework/file/52368b7bd633416588b15c6966093cf1.pdf',NULL,'5.%E3%80%8A%E5%BC%80%E5%BC%80%E7%BB%8F%E5%85%B8%E5%90%8D%E6%9B%B2%E5%AE%9D%E5%85%B8%E3%80%8B3.pdf',16655764,2000,0,'admin','admin','2026-04-16 18:22:49.830','2026-04-17 21:17:10.291'),(168,31,1,'TEXT','isEnrolled&&qwUserId_RLike','true&&default','同学，你好！老师刚听了你的演唱，明显你的歌唱状态比之前饱满了，歌唱的整体情绪越来越好。喉咙打开得不错，也用上了一些共鸣，但要注意保持住，还不稳定，时有时无的。',NULL,NULL,NULL,NULL,NULL,10000,1,'admin','api','2026-04-16 18:24:03.716','2026-04-16 18:24:03.716'),(169,31,2,'TEXT','isEnrolled&&qwUserId_RLike','true&&default','前面也说过你的气息目前不稳，导致音不太准，在这个作业里又出现了同样的问题。所以，想把歌唱好，这些基础的技术问题一定要先解决掉。后面的课程会对你帮助很大，学完后，你的歌声会好听翻倍。',NULL,NULL,NULL,NULL,NULL,10000,1,'admin','api','2026-04-16 18:24:38.810','2026-04-16 18:24:38.810'),(170,31,3,'TEXT','isEnrolled&&qwUserId_RLike','true&&default','其实，对于我们有生活阅历的人，唱起歌来比起小年轻更有味道，因为我们的内心经历比年轻人更丰富，情感表达也更深邃和准确。',NULL,NULL,NULL,NULL,NULL,5000,1,'admin','api','2026-04-16 18:24:59.941','2026-04-16 18:24:59.941'),(171,31,4,'TEXT','isEnrolled&&qwUserId_RLike','true&&default','老师希望你平时多来唱歌，多表达自己，用真实情感唱出的歌声是最打动人心的。但作为初学者，可能你会因为技术问题，无法淋漓尽致的去表现情感，声音总是欠些火候。只要你能坚定信心，跟着老师学完72节课，这些问题都会解决。以后你再也不会因为喜欢哪首歌却唱不好，而感到烦恼和遗憾了。',NULL,NULL,NULL,NULL,NULL,9000,1,'admin','api','2026-04-16 18:25:23.635','2026-04-16 18:25:23.635'),(172,31,5,'TEXT','isEnrolled&&qwUserId_RLike','true&&default','以你的嗓音，能把歌曲唱得更好听，你的信心和决心一定会为你未来的生活带来惊喜！希望能在后面的课程里见到你。最后祝贺你顺利结业，愿你的生活每天都有歌声陪伴，愿你健康快乐 ! 🌷',NULL,NULL,NULL,NULL,NULL,7000,1,'admin','api','2026-04-16 18:25:46.303','2026-04-16 18:25:46.303'),(173,31,6,'TEXT','isEnrolled&&qwUserId_RLike','false&&default','同学，你好！老师刚听了你的演唱，明显你的歌唱状态比之前饱满了，歌唱的整体情绪越来越好。喉咙打开得不错，也用上了一些共鸣，但要注意保持住，还不稳定，时有时无的。',NULL,NULL,NULL,NULL,NULL,6000,1,'admin','api','2026-04-16 18:26:06.568','2026-04-16 18:26:06.568'),(174,31,7,'TEXT','isEnrolled&&qwUserId_RLike','false&&default','前面也说过你的气息目前不稳，导致音不太准，在这个作业里又出现了同样的问题。所以，想把歌唱好，这些基础的技术问题一定要先解决掉。后面的课程会对你帮助很大，学完后，你的歌声会好听翻倍',NULL,NULL,NULL,NULL,NULL,7000,1,'admin','api','2026-04-16 18:26:36.161','2026-04-16 18:26:36.161'),(175,31,8,'TEXT','isEnrolled&&qwUserId_RLike','false&&default','其实，对于我们有生活阅历的人，唱起歌来比起小年轻更有味道，因为我们的内心经历比年轻人更丰富，情感表达也更深邃和准确。',NULL,NULL,NULL,NULL,NULL,7000,1,'admin','api','2026-04-16 18:26:58.116','2026-04-16 18:26:58.116'),(176,31,9,'TEXT','isEnrolled&&qwUserId_RLike','false&&default','老师希望你平时多来唱歌，多表达自己，用真实情感唱出的歌声是最打动人心的。但作为初学者，可能你会因为技术问题，无法淋漓尽致的去表现情感，声音总是欠些火候。只要你能坚定信心，跟着老师学完72节课，这些问题都会解决。以后你再也不会因为喜欢哪首歌却唱不好，而感到烦恼和遗憾了',NULL,NULL,NULL,NULL,NULL,8000,1,'admin','api','2026-04-16 18:27:25.966','2026-04-16 18:27:25.966'),(177,31,10,'TEXT','isEnrolled&&qwUserId_RLike','false&&default','以你的嗓音，能把歌曲唱得更好听，你的信心和决心一定会为你未来的生活带来惊喜！希望能在后面的课程里见到你。最后祝贺你体验课顺利结业，愿你的生活每天都有歌声陪伴，愿你健康快乐 ! 🌷',NULL,NULL,NULL,NULL,NULL,10000,1,'admin','api','2026-04-16 18:27:49.693','2026-04-16 18:27:49.693'),(178,31,11,'TEXT','isEnrolled&&qwUserId_RLike','false&&default','课程结束了，老师的系统课报名通道今晚24点关闭，您到底是怎么考虑的 呢？',NULL,NULL,NULL,NULL,NULL,6000,1,'admin','online_sql_20260423_remove_zhangman','2026-04-16 18:28:12.828','2026-04-23 16:42:47.000'),(179,31,12,'PDF','','',NULL,'https://kkhc.tos-cn-beijing.volces.com/mh/permanent/material/10603525-4bdc-45fe-aa93-2365d43711ee/%37%36%32%31%61%30%35%32%62%36%65%35%34%31%65%66%39%65%65%34%65%36%39%39%38%35%62%33%62%35%36%61.pdf','https://drh.likeduoduiyi.cn/homework/file/7621a052b6e541ef9ee4e69985b3b56a.pdf',NULL,'6.《开开护嗓宝典》.pdf',226681,8000,1,'admin','admin','2026-04-16 18:28:43.067','2026-04-16 18:28:43.067'),(180,33,2,'TEXT','','','不过当前提交的作业对应的课程还未开课，～',NULL,NULL,NULL,NULL,NULL,2000,1,'admin','admin','2026-04-16 19:16:22.013','2026-04-16 19:16:22.013'),(181,35,1,'TEXT','','','看到你主动提交作业了，积极性太赞啦！[强]',NULL,NULL,NULL,NULL,NULL,2000,0,'admin','admin','2026-04-16 19:29:00.406','2026-04-16 19:29:14.801'),(182,36,1,'TEXT','','','不过当前提交的作业对应的课程还未开课～',NULL,NULL,NULL,NULL,NULL,2000,0,'admin','admin','2026