292,26,8,'TEXT','lastDayCompleteHomeWork&&qwUserId_RLike','false&&default','同学，像啃食法呢，其实非常简单易操作，唱歌时每个字每个音我们都要用上刚开始你可能会觉得不习惯或者不舒服，我们多多练习就会慢慢形成习惯的。以后唱歌呢声音也会更立体继续加油练习哈',NULL,NULL,NULL,NULL,NULL,10000,1,'api','api','2026-04-22 18:09:19.869','2026-04-22 18:09:19.869'),(293,23,3,'VOICE','lastDayCompleteHomeWork&&qwUserId_RLike','true&&suiyiru,zhaoyuqing,liuyue,zhangtiange,zhengshili,peixiaojiao,wenxujuan,lihuichao,yanglifang,wangying,mufuqiang,shudie,xujie,zhouxu,xiewenhao,zhouyiting,youyihan,maiwei,lihongfu,xianghao,safangyi,zhangfuyi,chenke,taomeiyi,liuyongqi,zhangyangming,wujianpeng,zhengweipeng,jishending,lishidong,mupenglin,wujianxin,majun,xiejiaao,shiyanqing,zhutiantian,liupengxuan,huhuiqi',NULL,'https://kkhc.tos-cn-beijing.volces.com/eps-juzibot/permanent/material/%36%39%65%38%63%66%64%38%37%34%31%33%64%64%63%31%66%61%61%33%35%38%65%30.silk','https://drh.likeduoduiyi.cn/homework/voice/30674db2f4aa41ef867b1a71952d735a.m4a',24000,NULL,NULL,24000,1,'api','online_sql_20260427_append_shiyanqing_group_voice','2026-04-22 21:40:41.610','2026-04-27 17:18:21.000'),(294,23,4,'VOICE','lastDayCompleteHomeWork&&qwUserId_RLike','true&&suiyiru,zhaoyuqing,liuyue,zhangtiange,zhengshili,peixiaojiao,wenxujuan,lihuichao,yanglifang,wangying,mufuqiang,shudie,xujie,zhouxu,xiewenhao,zhouyiting,youyihan,maiwei,lihongfu,xianghao,safangyi,zhangfuyi,chenke,taomeiyi,liuyongqi,zhangyangming,wujianpeng,zhengweipeng,jishending,lishidong,mupenglin,wujianxin,majun,xiejiaao,shiyanqing,zhutiantian,liupengxuan,huhuiqi',NULL,'https://kkhc.tos-cn-beijing.volces.com/eps-juzibot/permanent/material/%36%39%65%38%63%66%64%61%33%38%37%36%30%32%65%64%37%64%37%38%38%63%64%33.silk','https://drh.likeduoduiyi.cn/homework/voice/955942f770614d4a9eaae9a23ba8bcb9.m4a',38000,NULL,NULL,38000,1,'api','online_sql_20260427_append_shiyanqing_group_voice','2026-04-22 21:40:42.920','2026-04-27 17:18:21.000'),(295,23,5,'VOICE','lastDayCompleteHomeWork&&qwUserId_RLike','true&&suiyiru,zhaoyuqing,liuyue,zhangtiange,zhengshili,peixi